using DrumPractice.Models;
using Microsoft.EntityFrameworkCore;

namespace DrumPractice.Data
{
    public static class SeedExercisesAndTags
    {
        private static readonly string[] Types = new[]
        {
            "Roll_Rudiments",
            "Diddle_Rudiments",
            "Flam_Rudiments",
            "Drag_Rudiments"
        };

        // Rudiment definitions
        private static readonly IEnumerable<RudimentDto> Rudiments = new List<RudimentDto>
        {
            new("01", "Single Stroke Roll",           Types[0], "https://www.youtube.com/watch?v=0_wgVPMRaiM&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=2", "This drum rudiment consists of alternating strokes played between the hands – R (right) L (left) R L R L…or L R L R L R…in case you’re left hand dominant. No matter the hand you start playing it with, it’s important you learn how to execute the single stroke roll leading with both hands."),
            new("02", "Single Stroke Four",           Types[0], "https://www.youtube.com/watch?v=YGqMJdIBpC0&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=13", "This drum rudiment is just a variation on the single stroke roll. Instead of having a consecutive stream (roll) of alternating single strokes, the single stroke four has four consecutive alternating single strokes played as triplets - hence its name. It should be counted, 1 trip let 2 3 trip let 4. Practice the single stroke four leading with both hands. Strive for consistent sounding strokes."),
            new("03", "Single Stroke Seven",          Types[0], "https://www.youtube.com/watch?v=VzdS_j_m3iY&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=14", "The single stroke seven builds on the single stroke roll and the single stroke four drum rudiments. Instead of having a consecutive stream (roll) of alternating strokes like on the single stroke roll, there are seven consecutive single strokes - hence the name single stroke seven. The single stroke seven is played in triplets, just like the single stroke four - 1 trip let 2 trip let 3. Think of this pattern as a single stroke four with three extra triplets added in. All strokes should sound the same. Practice the single stroke seven with both left hand and right hand leading."),
            new("04", "Multiple Bounce Roll",         Types[0], "https://www.youtube.com/watch?v=4ma9cS9iWzM&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=6", "The buzz roll is mostly associated with orchestral and marching band snare drumming. However, one can find this drum rudiment being used in numerous drum solos and on various styles of music like jazz, rock and Latin.\r\n\r\nThe multiple bounce roll consists of consecutive and alternating multiple bounce strokes, which are represented by the double diagonal lines on the note stems from the sheet music below. Each stroke has an undefined number of notes that are produced by pushing the stick into the drumhead or practice pad surface using a little bit of fulcrum pressure. The number of bounces is generated by the pressure you use on your fulcrum – the more pressure you use the less amount of bounces. Hence, it’s important you work on getting your hands to produce an even amount of pressure on the drumsticks. This is what will get you to have great sounding and consistent buzz roll.\r\n\r\nAs the stick bounces, you can relax a bit of the pressure on the fulcrum to make it easier to prepare for the next stroke. A common problem found in students that are first learning the multiple bounce roll is their tendency to squeeze the sticks with the back fingers. This kills most of the bounces, and it’s something you should avoid doing. Relax the back fingers and focus on the fulcrum pressure with the thumb and forefinger. Learn how to play the multiple bounce roll leading with both hands."),
            new("05", "Triple Stroke Roll",           Types[0], "https://www.youtube.com/watch?v=kUDEnUaDYvc&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=7", "With the single stroke roll you have one stroke per hand, with the double stroke roll two per hand, and as you can see on the sheet music below, with the triple stroke roll you play three alternating strokes. It’s very important for you to have a very solid knowledge of the single stroke and the double stroke roll drum rudiments before moving on to the triple stroke roll. They will help you master this one a lot quicker."),
            new("06", "Double Stroke Open Roll",      Types[0], "https://www.youtube.com/watch?v=IP_AzJIeYl4&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=5", "The double stroke roll is the second most important pattern of the 40 drum rudiments. The double stroke roll works just like the single stroke roll - it’s played in a sequence of alternating strokes (roll). But instead of having one stroke per hand you’ll have two. Focus on getting consistent sounding doubles for each hand. You can check your stroke evenness by watching your stick heights. Uniform distances from the drumhead to the drumstick for each stroke will hail even sounding doubles. If the first stroke of each set of doubles is louder than the second, your double stroke roll will sound sloppy and uneven."),
            new("07", "Five Stroke Roll",             Types[0], "https://www.youtube.com/watch?v=M5TpSYM3184&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=9", "The five stroke roll is pretty straight forward. You start by playing an alternating four-note double stroke roll led with your main hand. You follow this with a single stroke as the fifth note. Then, you alternate, and play the exact combination of notes but leading with your weaker hand instead."),
            new("08", "Six Stroke Roll",              Types[0], "https://www.youtube.com/watch?v=7zQmMK7uUAU&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=4", "The six stroke roll can be played in a couple of different ways. You can start by playing the two double strokes before playing the two singles, or start by executing the two singles before the two doubles. Another option to play the six stroke roll is as notated on the sheet music below - starting with a single, then two doubles followed by another single. The six stroke roll version taught by Lionel Duperron in this lesson is actually the pattern played on one of the greatest fills of all time – the “Motown drum fill” made famous by the great late Motown house drummer Richard “Pistol” Allen."),
            new("09", "Seven Stroke Roll",            Types[0], "https://www.youtube.com/watch?v=84CF8eH4bZw&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=20", "The seven stroke roll is one of the 40 drum rudiments than can alternate. Taking a look at the sheet music below, you can see that there is an 8th note gap between the first and the second seven stroke roll. At slow enough speeds, this gap gives you enough time to alternate your leading hand within the seven stroke roll, instead of always leading with the same.\r\nOnce you start speeding up the seven stroke roll, alternating can become really challenging. This is something you can work on later on in your 40 drum rudiments journey. For now learn how to execute the seven stroke roll leading with both hands."),
            new("10", "Nine Stroke Roll",             Types[0], "https://www.youtube.com/watch?v=BeeD25IkYVk&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=18", "Much like the five stroke roll, the nine stroke roll is one of the 40 drum rudiments than can naturally alternate. As you can see on the sheet music below, after playing the quarter note single stroke on count 3 there’s a quarter note rest. This will give you plenty of time to play the nine stroke roll leading with your weaker hand on the next measure."),
            new("11", "Ten Stroke Roll",              Types[0], "https://www.youtube.com/watch?v=9Mr6r2Fa_hk&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=39", "As you may be realizing by now, learning how to play the single stroke roll and the double stroke roll drum rudiments before trying this one out is imperative. The six stroke roll and nine stroke roll drum rudiments should also be learned before this one. They can work as great preliminary exercises for the ten stroke roll, since both have everything you need to know to be able to play it accurately. Knowing how to play these four drum rudiments before tackling the ten stroke roll will make it easier on you to master it."),
            new("12", "Eleven Stroke Roll",           Types[0], "https://www.youtube.com/watch?v=lTvXpve-WR4&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=52", "The structure of an eleven stroke roll is quite similar to the ones on the five stroke roll, seven stroke roll, and nine stroke roll drum rudiments. If you have practiced any of these drum rudiments beforehand you should have no problems at all with this one. This rudiment naturally changes the hand leading from measure to measure. Still, as you get to higher speeds it gets harder to do. So have that in mind while practicing the eleven stroke roll."),
            new("13", "Thirteen Stroke Roll",         Types[0], "https://www.youtube.com/watch?v=jt0VE9cxUBE&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=46", "It’s imperative you work through the free drum lessons on the single stroke roll and double stroke roll drum rudiments, before trying to learn the thirteen stroke roll. If you’ve been through other odd-numbered drum roll drum rudiments like the five stroke roll, seven stroke roll, nine stroke roll, and eleven stroke roll drum rudiments, you should find yourself working through this lesson pretty fast.\r\n\r\n"),
            new("14", "Fifteen Stroke Roll",          Types[0], "https://www.youtube.com/watch?v=0uXH5JRCVzM&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=24", "The underlying rhythm of a fifteen stroke roll is different from that of any other drum roll rudiment. You may find yourself struggling with this one at first because you keep playing the rhythms you are used to playing in other rolls, whether it is the seven stroke roll or the thirteen stroke roll. You have to practice the fifteen stroke roll so that its rhythmic pattern gets ingrained in your head. Also, with the fifteen stroke roll, you have a very big roll you need to keep consistent. Thus, practicing it will get your brain to learn to identify its rhythm, how to keep it clean and consistent, and how to play it flawlessly when you decide to use it."),
            new("15", "Seventeen Stroke Roll",        Types[0], "https://www.youtube.com/watch?v=MDGJRNbQBgg&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=47", "Having worked on drum rudiments like the five stroke roll, seven stroke roll, nine stroke roll, eleven stroke roll, thirteen stroke roll, or the fifteen stroke roll, will also help you getting through this lesson way faster. This is so because all of these drum rudiments encompass the same basic technical aspects in what regards execution - playing a stream of doubles and a single stroke after a double. "),
            new("16", "Single Paradiddle",            Types[1], "https://www.youtube.com/watch?v=h0OoVP6VgBE&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=1", "The single paradiddle is one of the most popular drum rudiments. It combines singles strokes with double strokes. So, if you haven’t worked on the single stroke roll and double stroke roll drum rudiments, check those free drum lessons first before going any further with this one.\r\n\r\nThe word “paradiddle” in the name of a rudiment, means that particular pattern has two single strokes (para) followed by one set of doubles (diddle). The word “single” in this particular case means you have one set of singles for each set of doubles. Thus, you can count the single paradiddle as such: R (par) L (a) R (did) R (dle) L (par) R (r) L (did) L (dle)."),
            new("17", "Double Paradiddle",            Types[1], "https://www.youtube.com/watch?v=_DkpHe5TZWk&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=3", "Just like the single paradiddle, the double paradiddle is also a great pattern for coming up with cool sounding drum beats and drum fills. It’s usually played as 8th note triplets or 16th note triplets, so it’s a great pattern for application to triplet based music. Make sure you count out loud when you practice the double paradiddle - 1 trip let 2 trip let 3 trip let 4 trip let. Due to its sticking pattern, the double paradiddle naturally alternates within itself."),
            new("18", "Triple Paradiddle",            Types[1], "https://www.youtube.com/watch?v=3tSSWNBs6xA&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=16", "The word “paradiddle” in the name of a rudiment, means that particular pattern has two single strokes (para) followed by one set of doubles (diddle). Having “triple” before “paradiddle”, means that the “para” is tripled. Thus, we’ll be having four extra single strokes – R (par) L (a) R (par) L (a) R (par) L (a) R (did) R (dle)."),
            new("19", "Single Paradiddle-Diddle",     Types[1], "https://www.youtube.com/watch?v=vVGsYTFy2yE&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=11", "This drum rudiment is a very fun one to study since it incorporates features from the single paradiddle and the double paradiddle. You can think of the single paradiddle-diddle as a single paradiddle with an extra diddle right after it - R (par) L (a) R (did) R (dle) L (did) L (dle). Much like the double paradiddle, the single paradiddle-diddle is usually played in either 8th note triplets or 16th note triplets. Thus, this is a great pattern to use in triplet based music. This is the only pattern from the paradiddle family of drum rudiments that doesn’t naturally alternate within itself, as you can see bellow. Thus, remember to practice this rudiment leading with both hands."),
            new("20", "Flam",                         Types[2], "https://www.youtube.com/watch?v=OhfjKnyk5-0&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=8", "The flam is actually a very though drum rudiment to play with great quality. Although you can play a grace note as far apart from the primary stroke as you wish to, for developing flam quality, you should practice this rudiment by playing the grace note as close to the primary stroke as possible. The secret for having great sounding flams is to keep your drumstick low whenever you’re prepping for executing a grace note. Also, you’ll want to avoid playing “flat flams” also known as “double stops” – when grace and primary notes are played in unison."),
            new("21", "Flam Accent",                  Types[2], "https://www.youtube.com/watch?v=JQzUtDgCwnI&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=26", "In the flam tap we had a double stroke roll played as 8th notes, where the first note was flammed. With the flam accent we have an 8th note triplet single stroke roll, where the first note is flammed. Thus, you need to have a good grasp on how to play the flam and the single stroke roll, before you can start thinking of mastering the flam accent. Taking a look at the sheet music below, you can see that after each flam there are two taps, and that the flam accent alternates within itself."),
            new("22", "Flam Tap",                     Types[2], "https://www.youtube.com/watch?v=nhF-ovLycks&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=17", "The Flam Tap is basically a double stroke roll where the first note is flammed. Hence, you need to have a good grasp on how to play the flam and the double stroke roll before even thinking of mastering the flam tap. The name of this drum rudiment tells us exactly how it is played – a flam followed by a tap (a single stroke)."),
            new("23", "Flamacue",                     Types[2], "https://www.youtube.com/watch?v=9lJ9DhVRX70&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=25", "If you’ve been through the lessons on the flam tap and flam accent drum rudiments, then it shouldn’t come to you as a shock that the flamacue incorporates another drum rudiment besides the flam. Taking a look at the sheet music below, if you drop the grace notes on all quarter notes and the accents on the “e” of counts 1 and 3, you can see that the main pattern inside the flamacue is actually a five stroke ruff (a ruff is a short single stroke roll). Thus, it’s important you check the lessons on the single stroke roll and the flam drum rudiments before going any further with this one."),
            new("24", "Flam Paradiddle",              Types[2], "https://www.youtube.com/watch?v=mFJvKONt1_Y&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=27", "The flam paradiddle continues with the same trend we’ve seen on all the other flam-based drum rudiments - combine the flam with other patterns from the 40 drum rudiments. In the case of the flam paradiddle, we have a single paradiddle combined with a flam. Taking a look at the sheet music below, you can see the sticking of a single paradiddle on the big letters – R L R R L R L L…etc. If you haven’t learned how to play the single paradiddle or the flam, now is a good time to do so."),
            new("25", "Single Flammed Mill",          Types[2], "https://www.youtube.com/watch?v=mlLUjZmGXuU&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=54", "The single flammed mill is one of the most interesting patterns to learn from the 40 drum rudiments. If you take a look at the big letters in the sheet music below, you can see that the main sticking for the single flammed mill is actually a reversed single paradiddle, also known as single mill.\r\n\r\nA single paradiddle is played as R L R R or as L R L L, while the single mill is played as R R L R or as L L R L. So, it’s important that you practice the single paradiddle first and foremost. This will make it a lot easier to learn how to play the reversed single paradiddle."),
            new("26", "Flam Paradiddle-Diddle",       Types[2], "https://www.youtube.com/watch?v=ek3AKKMSLAY&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=55", "Keeping with the tradition of the previous lessons on flam drum rudiments, the flam paradiddle-diddle (also known as flamadiddle-diddle) mixes the flam with another drum rudiment - the single paradiddle-diddle. Even before thinking of learning how to play the flam paradiddle-diddle, you have to make sure you have solid flams and single paradiddle-diddles, otherwise, mastering this lesson will be that much of a challenge. When you get to practice the flam paradiddle-diddle, you can count it as 8th note triplets – 1 trip let 2 tip let…etc. – or use the name of the rudiment instead – rL (flam or par) R (a) L (did) L (dle) R (did) R (dle)."),
            new("27", "Pataflafla",                   Types[2], "https://www.youtube.com/watch?v=vaP72Bw3K3o&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=23", "The pataflafla has one of the strangest names in the 40 drum rudiments. Taking a look at the sheet music below, you can see that it’s a combination of a 16th note single stroke roll with flams added on the “ahs” and on all quarter notes. The pataflafla played at faster tempos sounds pretty much like a Brazilian a samba pattern."),
            new("28", "Swiss Army Triplet",           Types[2], "https://www.youtube.com/watch?v=haNKfauXdis&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=10", "The Swiss army triplet was one of the last drum rudiments to be added to the 40 drum rudiments. It’s actually very similar to the flam accent. The flam accent is basically a single stroke roll with a flam on the first note, which is mostly played in triplets. The Swiss army triplet sounds just like a flam accent. Instead of being build upon a single stroke roll it has a double stroke with a flam on the first note, followed by a single stroke. As you can see from the sheet music below, the Swiss army triplet doesn’t alternate naturally within itself. You’ll have to learn how to play the Swiss army with both right hand and left hand lead."),
            new("29", "Inverted Flam Tap",            Types[2], "https://www.youtube.com/watch?v=VQPLlzEW5fg&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=49", "The inverted flam tap is a great reminder of how cool drum rudiments are as a tool to put your hand technique to the test. If you don’t look at the sticking on the flam tap and on the inverted flam tap drum rudiments, but look at their rhythmic pattern only, you can see they are identical drum rudiments. However, when you add in the sticking patterns you get totally different drum rudiments. So, these two drum rudiments can have very similar names and rhythmic notation, but they are different in their sticking patterns and in the way they challenge your technique.\r\n\r\nWhen compared to the inverted flam tap, the flam tap is an easier drum rudiment to master and to get up to speed. You can think of it as a double stroke roll with a flam on the first note. The sticking pattern in the inverted flam tap is an offset double stroke roll instead – the doubles start on the “and”. It’s this offset that gives it the moniker “inverted”, because the double stroke is starting on the tap instead of on the flam."),
            new("30", "Flam Drag",                    Types[2], "https://www.youtube.com/watch?v=4FOTuVjdsZQ&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=36", "The flam drag is usually played in triplets. Taking a look at the sheet music below, you can see that all the strokes in a flam drag are played as 8th note triplets, except for the “trip” of each count, which is a 16th note triplet double stroke. If you take the flam accent and the flam drag drum rudiments and put them side-by-side, you’ll notice that the main difference between them is really what it’s played on the “trip” of each count - a single stroke tap on the flam accent and a double stroke tap on the flam drag."),
            new("31", "Drag",                         Types[3], "https://www.youtube.com/watch?v=t2Tq7uKs4G8&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=15", "The drag ruff works a lot like the flam. It has two or more grace notes that are followed by a primary stroke. Two-stroke grace notes are played with bounced double strokes. You can add an undisclosed number of grace notes by buzzing them, that is, by using the multiple bounce roll, or buzz roll, instead of a double stroke roll.\r\n\r\nWe advise you to learn to play the drag ruff with either drum rudiments as grace notes - this gives you way more options. Hence, it’s imperative you work on your double stroke roll, multiple bounce roll, and single stroke roll drum rudiments before taking a stab on the drag ruff. The sheet music below shows a very simple drill to work on your hand-to-hand drag ruffs. Play the drag ruff as notated and with buzzed grace notes."),
            new("32", "Single Drag Tap",              Types[3], "https://www.youtube.com/watch?v=nQ--bjMHDfo&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=22", "Knowing how to play the drag ruff and the double stroke roll will make wonders for your single drag tap. Work on those two drum rudiments before going on with this free drum lesson. The single drag tap naturally alternates within itself. Work on the exercise below to get your single drag tap chops up to par, it’s a great exercise."),
            new("33", "Double Drag Tap",              Types[3], "https://www.youtube.com/watch?v=CfG5jAAi2R8&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=44", "If you put the two drum rudiments side-by-side you can see that just like the Swiss army triplet, the double drag tap has a double stroke followed by one single stroke. This is their only similarity. The double drag tap naturally alternates within itself and has two sets of grace notes, while the Swiss army triplet has only one grace note and does not alternate."),
            new("34", "Lesson 25",                    Types[3], "https://www.youtube.com/watch?v=SQkFLiVdK-M&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=33", "Lesson 25 is an interesting name to assign to a drum rudiment because it doesn’t appear to have a special meaning, nor does it tell us anything about the drum rudiment. Nonetheless, this is another pattern from the drag family of drum rudiments, and one you should definitely learn how to play correctly. Lesson 25 does not alternate, so practice leading it with both hands."),
            new("35", "Single Dragadiddle",           Types[3], "https://www.youtube.com/watch?v=lXi7C1LMs_g&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=31", "The single dragadiddle is very similar to the flam paradiddle and to the single paradiddle drum rudiments. The single dragadiddle starts with a 32nd note bounced double stroke, instead of with a flam (flam paradiddle) or with a single stroke (single paradiddle). The remaining strokes of the single dragadiddle are exactly the same. You can count the single dragadiddle as you count the flam paradiddle and the single paradiddle drum rudiments – RR (drag or par) L (a) R (did) R (dle) LL (drag or par) R (a) L (did) L (dle)…etc. It’s imperative you learn how to play the single paradiddle before taking on the single dragadiddle. The single dragadiddle alternates naturally within itself."),
            new("36", "Drag Paradiddle #1",           Types[3], "https://www.youtube.com/watch?v=oUytLscRNo4&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=42", "The dragadiddle #1 (also known as drag paradiddle #1) is one of the ten drum rudiments from the drag family of drum rudiments. In this free video drum lesson, Lionel Duperron takes you with him to the practice pad to show you how to play and practice the dragadiddle #1. Once he’s done teaching you the basics of the dragadiddle #1, Lionel makes his way to the drum set to show you some possible applications of the dragadiddle #1 to drum beats and drum fills."),
            new("37", "Drag Paradiddle #2",           Types[3], "https://www.youtube.com/watch?v=9uG5zrIPQ9c&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=60", "The dragadiddle #2 is heavily based on what was discussed and taught on the dragadiddle #1. If you haven’t taken the time to learn how to play the dragadiddle #1, please do so. Taking a look at the sheet music, you can see that the dragadiddle #2 is just like the dragadiddle #1, but with one extra dragged 8th note right after the quarter note single on the dragadiddle #1. If you lose the drags on the dragadiddle #2, you can see that the dragadiddle #2 is basically an 8th note double stroke followed by a 16th note single paradiddle. The dragadiddle #2 naturally alternates within itself, as you can see."),
            new("38", "Single Ratamacue",             Types[3], "https://www.youtube.com/watch?v=Wriq3khahO0&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=12", "The single ratamacue combines a single stroke four with a drag ruff. If you haven’t already, check the lessons on those two drum rudiments before tackling this one. The single ratamacue naturally alternates within itself. Practice the single ratamacue slowly at first. Use a metronome once you’re comfortable with its sticking pattern."),
            new("39", "Double Ratamacue",             Types[3], "https://www.youtube.com/watch?v=iEY4VXLzFp4&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=37", "If you’ve learned how to play the single ratamacue, you’ll have no problems in mastering the double ratamacue. The double ratamacue is basically a single ratamacue with a drag ruff played in front of it.\r\n\r\nThe double ratamacue naturally alternates within itself and is played in 6/8 time signature here. Playing in 6/8 means you’ll have 6 counts where the 8th notes take the click. Thus, the first double ratamacue on the sheet music below starts on count 1 and ends on count 3, while its second drag ruff is played on count 2. The second double ratamacue starts on count 4 and ends on count 6, while its second drag ruff is played on count 5."),
            new("40", "Triple Ratamacue",             Types[3], "https://www.youtube.com/watch?v=RP5SC45FBWA&list=PLThYwnIoLwyV_4OVK8Oj3idnHqX3qnTNR&index=45", "You can think of a triple ratamacue as a double ratamacue with an extra drag ruff in front of it. Take a look at the sheet music below to see what we mean by that. If you’ve taken the time to learn how to play a double ratamacue, you’ll have no problems in mastering the triple ratamacue. The triple ratamacue naturally alternates within itself. Once you can play the triple ratamacue accurately with a metronome, you can start working on the following triple ratamacue drum beats and drum fills.")
        };

        // Tag names that match the type strings but without underscore and plural.
        private static readonly Dictionary<string, string> TagNames = new()
        {
            { Types[0], "Roll Rudiment"  },
