            { Types[2], "Flam Rudiment"  },
            { Types[3], "Drag Rudiment"  }
        };

        public static void Seed(DataContext dbContext)
        {
            // --------------------------------------------------------------------
            // 1. Exercises
            // --------------------------------------------------------------------
            if (!dbContext.Exercises.Any())
            {
                var exercises = Rudiments.Select(r => new Exercise
                {
                    Name = r.Name,
                    Description = r.description,
                    ImageUrl = $"/images/40_International_Drum_Rudiments/rudiment-{r.ImageId}.png",
                    MediaUrl = r.MediaUrl
                });

                dbContext.Exercises.AddRange(exercises);
                dbContext.SaveChanges();
            }

            // --------------------------------------------------------------------
            // 2. Tags
            // --------------------------------------------------------------------
            if (!dbContext.Tags.Any())
            {
                var tags = TagNames.Values.Select(name => new Tag { Name = name });
                dbContext.Tags.AddRange(tags);
                dbContext.SaveChanges();
            }

            // --------------------------------------------------------------------
            // 3. ExerciseTag (many-to-many)
            // --------------------------------------------------------------------
            var exerciseDict = dbContext.Exercises
                .Include(e => e.Tags)
                .ToDictionary(e => e.Name, e => e);

            var tagDict = dbContext.Tags
                .Where(t => TagNames.Values.Contains(t.Name))
                .ToDictionary(t => t.Name, t => t);

            bool anyLinked = exerciseDict.Values.Any(e => e.Tags != null && e.Tags.Any());

            if (!anyLinked)
            {
                foreach (var rud in Rudiments)
                {
                    if (!exerciseDict.TryGetValue(rud.Name, out var exercise)) continue;
                    if (!TagNames.TryGetValue(rud.Type, out var tagName) || !tagDict.TryGetValue(tagName, out var tag)) continue;

                    exercise.Tags ??= new List<Tag>();
                    exercise.Tags.Add(tag);
                }

                dbContext.SaveChanges();
            }
        }

        private sealed record RudimentDto(string ImageId, string Name, string Type, string MediaUrl, string description);
    }
}
